INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('customs-f19eb2bd-moex-00247', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「美國科幻小說家雷‧布萊得伯利建議我們：既要學習接納別人的排斥， 也要學習排斥別人的接納。布萊得伯利的話嚴厲但實在，教我們以一種正 確的態度面對評論。當追求掌聲變成一種欲望，創作動機自然就變成對掌 聲的追求，這對作品可能是一種傷害。有些人對我們說好話，不見得是因 為作品，還有其他複雜的理由，例如人情關係等等；內行人對作品發表意 見，也有各種理由，未必著眼於作品，而更在反應這位內行人的其他思維。 我們要拿出自己的『測謊器』，辨識那些評論對我們是有幫助的。我們經 常忽略：批評最嚴厲的人，其實是我們的恩人；說最多好話的人，可能在 無形中害了我們。」 根據上文，下列選項何者最符合文意？', '["沒有評論不含複雜動機", "各種評論都應虛心採信", "讚美的背後必藏著毒藥", "迎合眾人可能扭曲創作"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00248', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '承上題，下列何者最符合上文對「內行人」的觀察？', '["有可能藉別人的作品談其他想法", "有時會為追求掌聲而褒揚創作者", "往往毫不留情面地嚴厲批評作品", "常自詡專業而不接納別人的排斥"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00249', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「有一家醫院為提升服務品質，改善對病人的醫療照護，請國際知名顧問 公司來幫忙。管理顧問提出各種炫目的流程圖與昂貴的資訊系統方案。後 來，這家醫院又找了另一家設計顧問公司來評估。這家設計人員將錄影機 架在自己頭上，躺在床上模擬病人錄下一天所看到的世界。設計公司發現， 病人一天中，一半以上的時間看不到『人類』，只看到天花板。他們唯一 能看到人的時候，是護士用輪椅帶他們去進行各種檢驗。所以，要如何改 善對病人的服務？醫師與護士看完影片後，決定不導入昂貴的資訊系統。 他們先布置天花板，用色彩繽紛的圖畫點綴，也在入口處放一個大白板， 讓探病的人留言。然後，他們在輪椅上裝一個照後鏡，讓病人可以在行進 中、說話時看到護士的臉，就這麼提升了服務品質。」 第二間顧問公司獲選的最主要原因是：', '["能同時滿足醫護人員與病人的多方需求", "能用更有創意的方法，提升管理的成效", "能理解醫院想節省經費解決問題的心理", "能從病人的角度發現問題，並找到解方"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00250', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '承上題，醫院改善服務品質的方式，不包括下列何者？', '["增加檢驗的次數讓病人更安心", "讓探病的人在入口白板上留言", "輪椅裝照後鏡增加與人的互動", "醫護人員花費心力布置天花板"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00251', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '有關海圖之精度（Accuracy）的敘述，下列何者錯誤？', '["測量日期較舊的海圖，精確度較差的原因是受到測量技術的影響", "位置的正確、測深點的疏密與海床覆蓋範圍特徵資訊的提供是精度的主要判斷因素", "有強烈橫向水流或河口港航道的等深線，其實際深度的變化相對較快", "進出危險水域或港區，應使用小比例尺（small-scale）海圖提供的資訊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00252', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '關於燈光的可見距離，國際能見距碼中編碼7「晴朗（Clear）」，其氣象光學能見距離（海浬）的區間為 下列何者？', '["1到2", "2到5.5", "5.5到11", "11到27"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00253', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '關於航船布告（NoticetoMariner）的各國機關發行單位之敘述，下列何者錯誤？', '["美國現為國家地理資訊局（NGA）、國家海洋與大氣總署（NOAA）與美國海巡署（USCG）聯合發行", "英國現為皇家海軍水文測量局（UKHO）", "我國現為海軍大氣海洋局、財政部關務署與行政院農業委員會漁業署", "日本現為海上保安廳（JCG）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00254', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '為了有效維持船舶的推算位置（DR），航行員必須遵守標註時機的原則，下列何者錯誤？', '["至少每整點鐘標註", "每當改變航向或航速時標註", "獲得定位或航進定位時標註", "天候或海象改變時標註"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00255', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '按照國際協議，海圖深度基準面之選擇，應以該地區之經常海平面極少會落於該潮汐基準面以下為宜，下 列何者不適合此協議？', '["平均低潮面（MLW）", "平均小潮高潮面（MHWN）", "平均大潮低潮面（MLWS）", "印度大潮低潮面（ISLW）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00256', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '為呼應淨零碳排放的國際趨勢，採用替代燃料的新造船因應而生，下列何者燃料的減碳效果最差？', '["Ammonia氨", "Hydrogen氫", "LNG液化天然氣", "Methanol甲醇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "8c6084d1518a", "answer_pdf_sha1": "0de76f111bf0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2006", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
